1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const DEDUCTIBLE = 100;
9	const CAP_MULTIPLIER = 2;
10	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
11	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const FIRST_INSURANCE_RATE = 0.1;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_THRESHOLD_YEARS = 2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	
36	function calculatePremiumParts(items: any[]): { policyBase: number; itemSurcharges: number } {
37	  const componentCounts: Record<string, number> = {};
38	  let policyBase = 0;
39	  let itemSurcharges = 0;
40	
41	  for (const item of items) {
42	    if (COMPONENT_TYPES.has(item.type)) {
43	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
44	    } else {
45	      const basePremium = BASE_PREMIUMS[item.type] || 0;
46	      policyBase += basePremium;
47	      if (item.cursed) {
48	        itemSurcharges += basePremium * CURSE_SURCHARGE_RATE;
49	      }
50	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
51	        itemSurcharges += basePremium * ENCHANTMENT_SURCHARGE_RATE;
52	      }
53	    }
54	  }
55	
56	  for (const type in componentCounts) {
57	    const count = componentCounts[type];
58	    if (count === BLOCK_SIZE) {
59	      policyBase += BLOCK_PREMIUM;
60	    } else {
61	      policyBase += count * COMPONENT_PREMIUM;
62	    }
63	  }
64	
65	  return { policyBase, itemSurcharges };
66	}
67	
68	function processQuote(items: any[], customer: any, quoteCount: number): { premium: number } {
69	  const { policyBase, itemSurcharges } = calculatePremiumParts(items);
70	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
71	    ? policyBase * LOYALTY_DISCOUNT_RATE
72	    : 0;
73	  const followUpDiscount = quoteCount > 0
74	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
75	    : 0;
76	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
77	  const premium = Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE);
78	  return { premium };
79	}
