81	interface Policy {
82	  items: any[];
83	  insuranceSum: number;
84	  remainingCap: number;
85	}
86	
87	export function processScenario(scenario: any): unknown {
88	  let quoteCount = 0;
89	  const policies: Record<number, Policy> = {};
90	
91	  const results = scenario.steps.map((step: any, index: number) => {
92	    if (step.op === "quote") {
93	      const items = step.items || [];
94	      const result = processQuote(items, scenario.customer, quoteCount);
95	      const insuranceSum = items.reduce(
96	        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] || 0),
97	        0,
98	      );
99	      policies[index] = {
100	        items,
101	        insuranceSum,
102	        remainingCap: insuranceSum * CAP_MULTIPLIER,
103	      };
104	      quoteCount++;
105	      return result;
106	    }
107	    if (step.op === "claim") {
108	      const policy = policies[step.policy];
109	      const damageCounts: Record<string, number> = {};
110	      for (const damage of step.incident.damages) {
111	        damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
112	      }
113	      for (const type in damageCounts) {
114	        const policyCount = policy.items.filter((i: any) => i.type === type).length;
115	        if (damageCounts[type] > policyCount) {
116	          throw new Error(`More damage entries for "${type}" than policy covers`);
117	        }
118	      }
119	      let totalPayout = 0;
120	      for (const damage of step.incident.damages) {
121	        const policyItem = policy.items.find((i: any) => i.type === damage.itemType)!;
122	        let reimbursement = damage.amount;
123	        if (policyItem.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
124	          reimbursement = damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
125	        }
126	        const payout = reimbursement - DEDUCTIBLE;
127	        totalPayout += Math.max(0, payout);
128	      }
129	      totalPayout = Math.min(totalPayout, policy.remainingCap);
130	      totalPayout = Math.floor(totalPayout);
131	      policy.remainingCap -= totalPayout;
132	      return { payout: totalPayout, remainingCap: policy.remainingCap };
133	    }
134	  });
135	  return { results };
136	}
